local grid = {}
local dirty = {}

for x = 1, #GRID_DATA do
  local row = {}
  local s = GRID_DATA[x]
  for y = 1, #s do
    local node = { x, y, s:byte(y) - 48, 0, 0, 0, false, false, nil }
    row[y] = node
  end
  grid[x] = row
end

local function clean_dirty()
  for i = 1, #dirty do
    local n = dirty[i]
    n[N_G] = 0
    n[N_H] = 0
    n[N_F] = 0
    n[N_VISITED] = false
    n[N_CLOSED] = false
    n[N_PARENT] = nil
  end
  dirty = {}
end

local function neighbors(x, y)
  local ret = {}
  local col = grid[x - 1]
  if col and col[y] then ret[#ret + 1] = col[y] end
  col = grid[x + 1]
  if col and col[y] then ret[#ret + 1] = col[y] end
  col = grid[x]
  if col[y - 1] then ret[#ret + 1] = col[y - 1] end
  if col[y + 1] then ret[#ret + 1] = col[y + 1] end
  return ret
end

local heap = {}

local function heap_push(node)
  local i = #heap + 1
  heap[i] = node
  local f = node[N_F]
  while i > 1 do
    local p = i >> 1
    if f < heap[p][N_F] then
      heap[i] = heap[p]
      heap[p] = node
      i = p
    else
      break
    end
  end
end

local function heap_pop()
  local result = heap[1]
  local n = #heap
  local last = heap[n]
  heap[n] = nil
  n = n - 1
  if n > 0 then
    heap[1] = last
    local i = 1
    local f = last[N_F]
    while true do
      local c1 = i << 1
      local c2 = c1 + 1
      local swap = 0
      local swap_f = f
      if c1 <= n and heap[c1][N_F] < f then
        swap = c1
        swap_f = heap[c1][N_F]
      end
      if c2 <= n and heap[c2][N_F] < swap_f then
        swap = c2
        swap_f = heap[c2][N_F]
      end
      if swap ~= 0 then
        heap[i] = heap[swap]
        heap[swap] = last
        i = swap
      else
        break
      end
    end
  end
  return result
end

local function heap_rescore(node)
  for idx = 1, #heap do
    if heap[idx] == node then
      local i = idx
      local f = node[N_F]
      while i > 1 do
        local p = i >> 1
        if f < heap[p][N_F] then
          heap[i] = heap[p]
          heap[p] = node
          i = p
        else
          break
        end
      end
      return
    end
  end
end

local function search(start_node, end_node)
  clean_dirty()
  heap = {}

  start_node[N_H] = math.abs(start_node[N_X] - end_node[N_X])
                      + math.abs(start_node[N_Y] - end_node[N_Y])
  dirty[#dirty + 1] = start_node
  heap_push(start_node)

  while #heap > 0 do
    local current = heap_pop()

    if current == end_node then
      local path = {}
      local curr = current
      while curr[N_PARENT] do
        path[#path + 1] = curr
        curr = curr[N_PARENT]
      end
      local result = {}
      for i = #path, 1, -1 do
        result[#result + 1] = path[i]
      end
      return result
    end

    current[N_CLOSED] = true

    local nbrs = neighbors(current[N_X], current[N_Y])
    for i = 1, #nbrs do
      local nb = nbrs[i]

      if not nb[N_CLOSED] and nb[N_WEIGHT] ~= 0 then
        local g_score = current[N_G] + nb[N_WEIGHT]
        local been_visited = nb[N_VISITED]

        if not been_visited or g_score < nb[N_G] then
          nb[N_VISITED] = true
          nb[N_PARENT] = current
          if nb[N_H] == 0 then
            nb[N_H] = math.abs(nb[N_X] - end_node[N_X])
                       + math.abs(nb[N_Y] - end_node[N_Y])
          end
          nb[N_G] = g_score
          nb[N_F] = g_score + nb[N_H]
          dirty[#dirty + 1] = nb

          if not been_visited then
            heap_push(nb)
          else
            heap_rescore(nb)
          end
        end
      end
    end
  end

  return {}
end

local result = search(grid[1][1], grid[124][322])

if #result ~= EXPECTED_LEN then
  print("bad path length: " .. #result .. " expected " .. EXPECTED_LEN)
  os.exit(1)
end

for i = 1, #result do
  local n = result[i]
  if n[N_X] ~= EXPECTED_PATH[i * 2 - 1] or n[N_Y] ~= EXPECTED_PATH[i * 2] then
    print("bad path at node " .. i)
    os.exit(1)
  end
end

print("ok")
